import {
  forwardRef,
  useCallback,
  useMemo,
  useRef,
  useState,
} from 'react';
import type { ListGroup } from '@arvo/core';
import ArvoActionMenu from '../ActionMenu/ActionMenu';
import type { MenuItemData } from '../ActionMenu/ActionMenu';
import { useTooltip, type TooltipProp } from '../../hooks/useTooltip';
import type { MenuSearchProp } from '../../types/menu-search';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ArvoDropdownButtonProps
  extends Omit<
    React.ButtonHTMLAttributes<HTMLButtonElement>,
    'disabled' | 'type' | 'onSelect' | 'defaultValue' | 'value'
  > {
  label: string;
  variant?: 'primary' | 'secondary' | 'tertiary' | 'outline';
  size?: 'sm' | 'md' | 'lg';
  icon?: string;
  mode?: 'action' | 'selection';
  displaySelected?: 'label' | 'value';
  value?: string | number | null;
  defaultValue?: string | number | null;
  isDisabled?: boolean;
  isLoading?: boolean;
  items: MenuItemData[] | ListGroup<MenuItemData>[];
  /** Enable search with defaults (`true`) or pass a config object. */
  search?: MenuSearchProp;
  placement?: 'top-start' | 'top-end' | 'bottom-start' | 'bottom-end';
  maxHeight?: string;
  hasGroupDividers?: boolean;
  closeOnSelect?: boolean;
  menuSize?: 'sm' | 'md';
  tooltip?: TooltipProp;
  onSelect?: (item: MenuItemData, index: number) => boolean | void;
  onOpen?: () => boolean | void;
  onClose?: () => boolean | void;
  onOpenChange?: (isOpen: boolean) => void;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function isGrouped(
  items: MenuItemData[] | ListGroup<MenuItemData>[],
): items is ListGroup<MenuItemData>[] {
  return items.length > 0 && 'items' in items[0];
}

function flattenItems(
  items: MenuItemData[] | ListGroup<MenuItemData>[],
): MenuItemData[] {
  if (isGrouped(items)) return items.flatMap((g) => g.items);
  return items as MenuItemData[];
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const ArvoDropdownButton = forwardRef<HTMLButtonElement, ArvoDropdownButtonProps>(
  function ArvoDropdownButton(
    {
      label,
      variant = 'primary',
      size = 'md',
      icon,
      mode = 'action',
      displaySelected = 'label',
      value,
      defaultValue = null,
      isDisabled = false,
      isLoading = false,
      items,
      search,
      placement = 'bottom-end',
      maxHeight,
      hasGroupDividers = true,
      closeOnSelect = true,
      menuSize = 'md',
      tooltip,
      className,
      onSelect,
      onOpen,
      onClose,
      onOpenChange,
      onClick,
      onFocus,
      onBlur,
      ...rest
    },
    ref,
  ) {
    const triggerRef = useRef<HTMLButtonElement | null>(null);

    useTooltip({ triggerRef, tooltip });

    // ── Open state (for caret rotation) ─────────────────────────────────
    const [isOpen, setIsOpen] = useState(false);

    // ── Selection state ─────────────────────────────────────────────────
    const isControlled = value !== undefined;
    const [internalSelected, setInternalSelected] = useState<
      string | number | null
    >(defaultValue);
    const effectiveSelectedId = isControlled ? value : internalSelected;

    const flat = useMemo(() => flattenItems(items), [items]);

    const selectedItemData = useMemo(() => {
      if (effectiveSelectedId == null) return null;
      const id = String(effectiveSelectedId);
      return flat.find((item) => item.id === id) ?? null;
    }, [flat, effectiveSelectedId]);

    const displayLabel = useMemo(() => {
      if (mode === 'action' || !selectedItemData) return label;
      if (displaySelected === 'value') {
        const val = (selectedItemData as unknown as Record<string, unknown>).value;
        return val != null ? String(val) : selectedItemData.id;
      }
      return selectedItemData.label;
    }, [mode, selectedItemData, label, displaySelected]);

    // ── Open-change handler ─────────────────────────────────────────────
    const handleOpenChange = useCallback(
      (isOpen: boolean) => {
        setIsOpen(isOpen);
        onOpenChange?.(isOpen);
      },
      [onOpenChange],
    );

    // ── Process items (mark selected in selection mode) ─────────────────
    const processedItems = useMemo(() => {
      if (mode !== 'selection' || effectiveSelectedId == null) return items;

      const selId = String(effectiveSelectedId);
      const mark = (item: MenuItemData): MenuItemData => ({
        ...item,
        active: item.id === selId,
      });

      if (isGrouped(items)) {
        return items.map((group) => ({
          ...group,
          items: group.items.map(mark),
        }));
      }
      return (items as MenuItemData[]).map(mark);
    }, [items, mode, effectiveSelectedId]);

    // ── Selection handler ───────────────────────────────────────────────
    const handleSelect = useCallback(
      (item: MenuItemData, index: number) => {
        if (mode === 'selection') {
          const prevId = isControlled ? value : internalSelected;
          const previousItem =
            prevId != null
              ? flat.find((i) => i.id === String(prevId)) ?? null
              : null;

          if (!isControlled) setInternalSelected(item.id);

          triggerRef.current?.dispatchEvent(
            new CustomEvent('dd-btn:change', {
              bubbles: true,
              cancelable: true,
              detail: { item, index, previousItem },
            }),
          );
        } else {
          triggerRef.current?.dispatchEvent(
            new CustomEvent('dd-btn:select', {
              bubbles: true,
              cancelable: true,
              detail: { item, index },
            }),
          );
        }

        return onSelect?.(item, index);
      },
      [mode, isControlled, value, internalSelected, flat, onSelect],
    );

    // ── Ref merging ─────────────────────────────────────────────────────
    const mergeRef = useCallback(
      (node: HTMLButtonElement | null) => {
        triggerRef.current = node;
        if (typeof ref === 'function') {
          ref(node);
        } else if (ref) {
          (ref as React.MutableRefObject<HTMLButtonElement | null>).current =
            node;
        }
      },
      [ref],
    );

    // ── Trigger classes ─────────────────────────────────────────────────
    const triggerClasses = [
      'arvo-dd-btn',
      'arvo-btn',
      `arvo-btn--${variant}`,
      `arvo-btn--${size}`,
      isOpen && 'open',
      isLoading && 'loading',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    // ── Trigger element ─────────────────────────────────────────────────
    const triggerElement = (
      <button
        ref={mergeRef}
        type="button"
        {...rest}
        className={triggerClasses}
        disabled={isDisabled}
        aria-busy={isLoading || undefined}
        onClick={onClick}
        onFocus={onFocus}
        onBlur={onBlur}
      >
        {icon && (
          <span
            className={`arvo-dd-btn__icon o9con o9con-${icon}`}
            aria-hidden="true"
          />
        )}
        <span className="arvo-dd-btn__lbl">{displayLabel}</span>
        <span
          className="arvo-dd-btn__caret o9con o9con-angle-down"
          aria-hidden="true"
        />
      </button>
    );

    // ── Render ───────────────────────────────────────────────────────────
    return (
      <ArvoActionMenu
        trigger={triggerElement}
        items={processedItems}
        size={menuSize}
        placement={placement}
        search={search}
        maxHeight={maxHeight}
        hasGroupDividers={hasGroupDividers}
        closeOnSelect={closeOnSelect}
        isDisabled={isDisabled || isLoading}
        isLoading={false}
        onOpen={onOpen}
        onClose={onClose}
        onSelect={handleSelect}
        onOpenChange={handleOpenChange}
      />
    );
  },
);

export default ArvoDropdownButton;
